import{_ as n,C as o,o as r,c as l,j as t,a as i,E as s,ag as g}from"./chunks/framework.CvgP6Fyv.js";const P=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),d={name:"changelog.md"},c={id:"v1-0-0",tabindex:"-1"};function m(u,e,p,h,f,S){const a=o("Badge");return r(),l("div",null,[e[3]||(e[3]=t("h1",{id:"changelog",tabindex:"-1"},[i("Changelog "),t("a",{class:"header-anchor",href:"#changelog","aria-label":'Permalink to "Changelog"'},"​")],-1)),e[4]||(e[4]=t("p",null,"All notable changes to SendGrail are documented on this page.",-1)),t("h2",c,[e[0]||(e[0]=i("v1.0.0 ",-1)),s(a,{type:"tip",text:"Initial Release"}),e[1]||(e[1]=i()),e[2]||(e[2]=t("a",{class:"header-anchor",href:"#v1-0-0","aria-label":'Permalink to "v1.0.0 <Badge type="tip" text="Initial Release" />"'},"​",-1))]),e[5]||(e[5]=g('<p><em>Released: 2026-03-28</em></p><h3 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h3><ul><li><strong>SMTP Connections</strong> -- Create and manage multiple SMTP connections with support for 13 pre-configured providers (Gmail, Outlook, Yahoo, SendGrid, Mailgun, Amazon SES, Postmark, Mandrill, Elastic Email, SMTP2GO, Mailtrap, Zoho Mail, Brevo) plus custom SMTP.</li><li><strong>Default and Fallback Connections</strong> -- Set a primary connection for all outgoing email with an optional fallback connection for automatic failover.</li><li><strong>Email Logging</strong> -- Log all outgoing emails with full metadata including recipients, subject, status, and timestamps. Optional full body storage.</li><li><strong>Open Tracking</strong> -- Track email opens via an invisible tracking pixel injected into HTML emails.</li><li><strong>Click Tracking</strong> -- Track link clicks by routing through a tracking endpoint before redirecting to the original URL.</li><li><strong>Smart Routing</strong> -- Route emails through different SMTP connections based on sender address, recipient, or domain rules.</li><li><strong>Setup Wizard</strong> -- Guided five-step wizard for first-time configuration with automatic provider detection and credential validation.</li><li><strong>One-Click Migration</strong> -- Import SMTP settings from WP Mail SMTP, Post SMTP, FluentSMTP, and Easy WP SMTP with a single click.</li><li><strong>Test Email</strong> -- Send test emails directly from the connection management interface to verify credentials and delivery.</li><li><strong>Connection Validation</strong> -- Validate SMTP credentials at save time with clear error reporting.</li><li><strong>Failure Notifications</strong> -- Receive email alerts when delivery fails through all configured connections.</li><li><strong>Weekly Summary Reports</strong> -- Scheduled email reports with delivery statistics, failure counts, and engagement metrics.</li><li><strong>Dashboard</strong> -- Overview of recent email activity, delivery success rates, and connection status at a glance.</li><li><strong>Log Retention</strong> -- Automatic cleanup of email logs older than the configured retention period.</li><li><strong>WordPress Default Mail Fallback</strong> -- Optional last-resort fallback to PHP <code>mail()</code> when all SMTP connections fail.</li><li><strong>Debug Mode</strong> -- Detailed SMTP transaction logging to <code>wp-content/debug.log</code> for troubleshooting.</li><li><strong>Dark and Light Themes</strong> -- Admin interface supports both dark and light themes with automatic detection.</li><li><strong>UTC Date Standardization</strong> -- All dates stored and displayed in UTC for consistency across time zones.</li></ul>',3))])}const k=n(d,[["render",m]]);export{P as __pageData,k as default};
